use anyhow::{Context, Result};
use serde::{Deserialize, Serialize};
use std::collections::BTreeMap;
use std::fs;
use std::path::{Path, PathBuf};
use std::time::{SystemTime, UNIX_EPOCH};

use super::traffic::TrafficSnapshot;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BenchmarkRun {
    pub name: String,
    pub workload: String,
    pub concurrency: usize,
    pub duration_seconds: u64,
    pub snapshot: TrafficSnapshot,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BenchmarkReport {
    pub schema_version: u32,
    pub label: String,
    pub generated_at_unix_seconds: u64,
    pub api_url: String,
    pub redirect_url: String,
    pub runs: Vec<BenchmarkRun>,
}

#[derive(Debug, Clone)]
struct BaselineMetrics {
    requests_per_second: f64,
    p99_ms: f64,
}

pub fn new_report(label: String, api_url: String, redirect_url: String) -> Result<BenchmarkReport> {
    Ok(BenchmarkReport {
        schema_version: 1,
        label,
        generated_at_unix_seconds: SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .context("system clock predates Unix epoch")?
            .as_secs(),
        api_url,
        redirect_url,
        runs: Vec::new(),
    })
}

pub fn write_report(
    output_dir: &Path,
    report: &BenchmarkReport,
    baseline_path: Option<&Path>,
) -> Result<PathBuf> {
    fs::create_dir_all(output_dir)
        .with_context(|| format!("create benchmark output directory {}", output_dir.display()))?;

    let json_path = output_dir.join(format!("native-benchmark-{}.json", report.label));
    let markdown_path = output_dir.join(format!("native-benchmark-{}.md", report.label));
    fs::write(
        &json_path,
        serde_json::to_string_pretty(report).context("serialize benchmark JSON")?,
    )
    .with_context(|| format!("write {}", json_path.display()))?;

    let comparison = baseline_path
        .map(load_baseline)
        .transpose()?
        .unwrap_or_default();
    fs::write(&markdown_path, render_markdown(report, &comparison))
        .with_context(|| format!("write {}", markdown_path.display()))?;
    fs::write(
        output_dir.join("INDEX.md"),
        render_index(report, &markdown_path, &json_path),
    )
    .with_context(|| format!("write benchmark index in {}", output_dir.display()))?;

    Ok(markdown_path)
}

fn load_baseline(path: &Path) -> Result<BTreeMap<String, BaselineMetrics>> {
    let baseline: BenchmarkReport = serde_json::from_slice(
        &fs::read(path).with_context(|| format!("read baseline report {}", path.display()))?,
    )
    .with_context(|| format!("decode baseline report {}", path.display()))?;
    Ok(baseline
        .runs
        .iter()
        .map(|run| {
            (
                run.name.clone(),
                BaselineMetrics {
                    requests_per_second: run.snapshot.requests_per_second,
                    p99_ms: run.snapshot.p99_ms,
                },
            )
        })
        .collect())
}

fn render_markdown(
    report: &BenchmarkReport,
    baseline: &BTreeMap<String, BaselineMetrics>,
) -> String {
    let mut markdown = format!(
        "# Lynx Native Rust Benchmark Report\n\n\
         - **Label:** {}\n\
         - **Generated (Unix):** {}\n\
         - **API:** {}\n\
         - **Redirect:** {}\n\n\
         All traffic was generated by the typed Rust harness using bounded reqwest workers; no external load generator was used.\n\n\
         ## Stage Results\n\n\
         | Stage | Workload | Concurrency | Requests | Success | Errors | RPS | P50 ms | P95 ms | P99 ms |\n\
         |---|---|---:|---:|---:|---:|---:|---:|---:|---:|\n",
        report.label, report.generated_at_unix_seconds, report.api_url, report.redirect_url
    );

    for run in &report.runs {
        let snapshot = &run.snapshot;
        markdown.push_str(&format!(
            "| {} | {} | {} | {} | {} | {} | {:.2} | {:.3} | {:.3} | {:.3} |\n",
            run.name,
            run.workload,
            run.concurrency,
            snapshot.total,
            snapshot.success,
            snapshot.total.saturating_sub(snapshot.success),
            snapshot.requests_per_second,
            snapshot.p50_ms,
            snapshot.p95_ms,
            snapshot.p99_ms,
        ));
    }

    if !baseline.is_empty() {
        markdown.push_str("\n## Baseline Comparison\n\n");
        markdown.push_str("| Stage | Baseline RPS | Candidate RPS | RPS change | Baseline P99 ms | Candidate P99 ms | P99 change ms |\n|---|---:|---:|---:|---:|---:|---:|\n");
        for run in &report.runs {
            if let Some(baseline) = baseline.get(&run.name) {
                let candidate_rps = run.snapshot.requests_per_second;
                let rps_change = if baseline.requests_per_second == 0.0 {
                    0.0
                } else {
                    (candidate_rps - baseline.requests_per_second) / baseline.requests_per_second
                        * 100.0
                };
                let candidate_p99 = run.snapshot.p99_ms;
                markdown.push_str(&format!(
                    "| {} | {:.2} | {:.2} | {rps_change:+.2}% | {:.3} | {:.3} | {:+.3} |\n",
                    run.name,
                    baseline.requests_per_second,
                    candidate_rps,
                    baseline.p99_ms,
                    candidate_p99,
                    candidate_p99 - baseline.p99_ms,
                ));
            }
        }
    }

    markdown
}

fn render_index(report: &BenchmarkReport, markdown_path: &Path, json_path: &Path) -> String {
    format!(
        "# Native Benchmark Artifacts\n\n\
         - [Human-readable report]({})\n\
         - [Typed JSON data]({})\n\n\
         {} traffic stages were measured by the Rust-native harness.\n",
        markdown_path
            .file_name()
            .unwrap_or_default()
            .to_string_lossy(),
        json_path.file_name().unwrap_or_default().to_string_lossy(),
        report.runs.len(),
    )
}
